def get_player_move():
    # Prompt player for move in notation (e.g., '4 2 3 1')
    start_col = int(input("Enter starting column: "))
    start_row = int(input("Enter starting row: "))
    end_col = int(input("Enter ending column: "))
    end_row = int(input("Enter ending row: "))
    return start_row, start_col, end_row, end_col

def main():
    board = Board()
    turn = 'R'
    while True:
        board.print_board()
        print(f"Player {turn}'s turn")
        move = get_player_move()
        if board.valid_move(move[0], move[1], move[2], move[3]):
            board.move_piece(*move)
            result = board.check_win()
            if result:
                print(result)
                break
            result = board.check_draw()
            if result:
                print(result)
                break
            turn = 'B' if turn == 'R' else 'R'
        else:
            print("Invalid move. Try again.")

if __name__ == "__main__":
    main()
```

